function findKthLargest(nums, k) {
  // Min heap using array (JavaScript doesn't have built-in heap)
  const minHeap = [];

  function heapifyUp(index) {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (minHeap[parent] <= minHeap[index]) break;
      [minHeap[parent], minHeap[index]] = [minHeap[index], minHeap[parent]];
      index = parent;
    }
  }

  function heapifyDown(index) {
    while (true) {
      let smallest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < minHeap.length && minHeap[left] < minHeap[smallest]) {
        smallest = left;
      }
      if (right < minHeap.length && minHeap[right] < minHeap[smallest]) {
        smallest = right;
      }
      if (smallest === index) break;

      [minHeap[index], minHeap[smallest]] = [minHeap[smallest], minHeap[index]];
      index = smallest;
    }
  }

  // Build heap of size k
  for (const num of nums) {
    if (minHeap.length < k) {
      minHeap.push(num);
      heapifyUp(minHeap.length - 1);
    } else if (num > minHeap[0]) {
      minHeap[0] = num;
      heapifyDown(0);
    }
  }

  return minHeap[0];
}

